import { getValidColorPalette } from './get-valid-color-palette.js';
import { getColorPalette } from '../../../../core/utils/get-color-palette.js';
import { DEFAULT_COLOR_PALETTE } from '../../../constants/defaults.js';
import type {
  XYChartAreaSeriesInternal,
  XYChartBarSeriesInternal,
  XYChartDotSeriesInternal,
  XYChartLineSeriesInternal,
} from '../../../types/xy-chart-internals.js';
import type {
  XYChartColorPalette,
  XYChartData,
} from '../../../types/xy-chart.js';
import {
  getColorPaletteSelection,
  getColorSelection,
} from '../../../utils/coloring/get-color-selection.js';

export function getLinearColor(
  datum: XYChartData,
  seriesProps:
    | XYChartDotSeriesInternal
    | XYChartBarSeriesInternal
    | XYChartLineSeriesInternal
    | XYChartAreaSeriesInternal,
  configColorPalette: XYChartColorPalette | undefined,
  seriesName: string,
  seriesIndex: number,
) {
  const validatedColorPalette =
    getColorPaletteSelection(seriesProps.colorPalette, datum) ??
    configColorPalette ??
    DEFAULT_COLOR_PALETTE;

  const assignedColor = getColorPalette(
    seriesName,
    seriesIndex,
    // @ts-expect-error - todo
    validatedColorPalette,
  );
  const colorSelection =
    getColorSelection(seriesProps.color, datum) ?? assignedColor;

  const validColorPalette = getValidColorPalette(
    configColorPalette,
    validatedColorPalette,
  );

  const validColor = colorSelection
    ? colorSelection
    : getColorPalette(
        seriesName,
        seriesIndex,
        // @ts-expect-error - todo
        validColorPalette,
      );

  return {
    color: validColor,
    colorPalette: validColorPalette,
    colorIsFromSlot:
      !!seriesProps.color || validatedColorPalette === seriesProps.colorPalette,
  };
}
